    const txt = (el.textContent || '').replace(/\s+/g, ' ').trim();
    if (txt === 'Elija una marca' || /^Elija una marca$/i.test(txt)) {
      marcaNode = el; break;
    }
  }
  // Climb to the closest form/section/div container
  let sel = marcaNode;
  for (let i = 0; i < 12 && sel; i++) {
    sel = sel.parentElement;
