await tryWithReferer('https://www.autodoc.es/assets/54eb94/fonts/Montserrat-VariableFont_wght.ttf', path.join(FONTS, 'Montserrat-VariableFont_wght.ttf'));
log('total captured:', captures.length);
await browser.close();

