.slick-arrow:hover { background: #ffffff; }
.slick-arrow.slick-prev { left: 12px; }
.slick-arrow.slick-next { right: 12px; }
.slick-dots {
  position: absolute; bottom: 14px; left: 50%; transform: translateX(-50%);
